const clientId = 'YOUR_CLIENT_ID';
const redirectUri = 'YOUR_REDIRECT_URI';
const authEndpoint = 'https://authorization-server.com/auth';
const responseType = 'token';
const scope = 'YOUR_SCOPES';

function login() {
  const authUrl = `${authEndpoint}?response_type=${responseType}&client_id=${encodeURIComponent(clientId)}&redirect_uri=${encodeURIComponent(redirectUri)}&scope=${encodeURIComponent(scope)}`;
  window.location.href = authUrl;
}

function getAccessTokenFromUrl() {
  const hash = window.location.hash.substring(1);
  const params = new URLSearchParams(hash);
  return params.get('access_token');
}

function storeAccessToken(token) {
  sessionStorage.setItem('access_token', token);
}

function getStoredAccessToken() {
  return sessionStorage.getItem('access_token');
}

function clearAccessToken() {
  sessionStorage.removeItem('access_token');
}

function makeApiCall(endpoint) {
  const token = getStoredAccessToken();
  if (!token) {
    console.error('No access token available');
    return;
  }

  fetch(endpoint, {
    headers: {
      'Authorization': `Bearer ${token}`
    }
  })
  .then(response => response.json())
  .then(data => console.log(data))
  .catch(error => console.error('Error:', error));
}

window.onload = function() {
  const token = getAccessTokenFromUrl();
  if (token) {
    storeAccessToken(token);
    window.location.hash = ''; // Clear the fragment to prevent token leakage
  }
};

